using System.Net.Http.Json;using System.Security.Cryptography;using System.Text;using System.Text.Json;using System.Text.Json.Serialization;using Microsoft.Extensions.Configuration;using SmartDine.Application.Constants;using SmartDine.Domain.Interfaces;namespace SmartDine.Infrastructure.ExternalServices;/// <summary>/// T+Ąch hß+úp cß+ōng thanh to+ín PayOS (payos.vn) qua REST API.////// Credentials tß+― appsettings["PayOS"]: ClientId, ApiKey, ChecksumKey./// Endpoint: https://api-merchant.payos.vn/v2/payment-requests////// Ai d+Ķng: -æĶĶß+úc inject v+áo PaymentService qua IPaymentGateway interface./// Test: thay bßĶĶng MockPaymentGateway (kh+Ķng cßĶšn network thßĶĄt).////// T+ái liß+įu PayOS: https://payos.vn/docs/api/// </summary>public class PayOsGateway : IPaymentGateway{    private readonly HttpClient _http;    private readonly string _clientId;    private readonly string _apiKey;    private readonly string _checksumKey;    private const string BaseUrl = "https://api-merchant.payos.vn/v2/payment-requests";    public PayOsGateway(HttpClient http, IConfiguration config)    {        _http = http;        _clientId = config["PayOS:ClientId"]            ?? throw new InvalidOperationException(ValidationMessages.PAYOS_CONFIG_CLIENTID_MISSING);        _apiKey = config["PayOS:ApiKey"]            ?? throw new InvalidOperationException(ValidationMessages.PAYOS_CONFIG_APIKEY_MISSING);        _checksumKey = config["PayOS:ChecksumKey"]            ?? throw new InvalidOperationException(ValidationMessages.PAYOS_CONFIG_CHECKSUMKEY_MISSING);        _http.DefaultRequestHeaders.Add("x-client-id", _clientId);        _http.DefaultRequestHeaders.Add("x-api-key", _apiKey);    }    /// <summary>    /// Gß+ėi PayOS API tßĶío link thanh to+ín cho 1 -æĶín h+áng.    /// TrßĶú vß+ü CheckoutUrl (deeplink) + QrCode (raw EMV string).    ///    /// PayOS y+Žu cßĶšu amount l+á sß+æ nguy+Žn (VND), kh+Ķng c+Ķ phßĶšn thßĶĄp ph+ón.    /// orderCode phßĶúi unique trong hß+į thß+æng merchant.    /// </summary>    public async Task<GatewayCreatePaymentResult> CreatePaymentLinkAsync(        long orderCode, int amount, string description, string returnUrl, string cancelUrl)    {        // PayOS y+Žu cßĶšu signature = HMAC-SHA256 cß+ša c+íc field ch+Ąnh, sßĶŧp xßĶ+p theo alphabet        var dataToSign = $"amount={amount}&cancelUrl={cancelUrl}&description={description}&orderCode={orderCode}&returnUrl={returnUrl}";        var signature = ComputeHmacSha256(dataToSign, _checksumKey);        var body = new        {            orderCode,            amount,            description,            cancelUrl,            returnUrl,            signature,            items = new[]            {                new { name = "H+Ķa -æĶín", quantity = 1, price = amount }            }        };        try        {            var response = await _http.PostAsJsonAsync(BaseUrl, body);            var json = await response.Content.ReadFromJsonAsync<PayOsApiResponse>();            if (json?.Code != "00" || json.Data == null)                return new GatewayCreatePaymentResult(false, null, null, null, 0,                    json?.Desc ?? "PayOS trßĶú vß+ü lß+ųi kh+Ķng x+íc -æß+ïnh.");            return new GatewayCreatePaymentResult(                Success: true,                CheckoutUrl: json.Data.CheckoutUrl,                QrCode: json.Data.QrCode,                PaymentLinkId: json.Data.PaymentLinkId,                OrderCode: json.Data.OrderCode);        }        catch (Exception ex)        {            return new GatewayCreatePaymentResult(false, null, null, null, 0,                $"Lß+ųi kßĶ+t nß+æi cß+ōng thanh to+ín: {ex.Message}");        }    }    /// <summary>    /// X+íc minh webhook tß+― PayOS bßĶĶng HMAC-SHA256.    ///    /// ThußĶĄt to+ín:    ///   1. LßĶŅy tßĶŅt cßĶú key-value trong data object, sßĶŧp xßĶ+p key theo alphabet.    ///   2. Nß+æi th+ánh chuß+ųi "key1=value1&amp;key2=value2&amp;...".    ///   3. HMAC-SHA256 chuß+ųi -æ+Ķ vß+Ēi ChecksumKey GåÆ so s+ính vß+Ēi signature trong body.    ///    /// TrßĶú vß+ü null nßĶ+u signature sai GĮö caller phßĶúi reject request ngay.    /// </summary>    public GatewayWebhookData? VerifyAndParseWebhook(string webhookBody, string? signature)    {        try        {            var doc = JsonDocument.Parse(webhookBody);            var root = doc.RootElement;            // LßĶŅy data object -æß+â verify            if (!root.TryGetProperty("data", out var dataEl))                return null;            // Build sorted query string tß+― data fields            var sortedFields = new SortedDictionary<string, string>(StringComparer.Ordinal);            foreach (var prop in dataEl.EnumerateObject())            {                var val = prop.Value.ValueKind switch                {                    JsonValueKind.Null    => "",                    JsonValueKind.String  => prop.Value.GetString() ?? "",                    JsonValueKind.Number  => prop.Value.GetRawText(),                    JsonValueKind.True    => "true",                    JsonValueKind.False   => "false",                    _                     => prop.Value.GetRawText()                };                sortedFields[prop.Name] = val;            }            var dataStr = string.Join("&", sortedFields.Select(kv => $"{kv.Key}={kv.Value}"));            var expectedSig = ComputeHmacSha256(dataStr, _checksumKey);            // LßĶŅy signature tß+― body (nßĶ+u kh+Ķng truyß+ün qua header)            var bodySig = signature;            if (string.IsNullOrEmpty(bodySig) && root.TryGetProperty("signature", out var sigEl))                bodySig = sigEl.GetString();            if (!string.Equals(expectedSig, bodySig, StringComparison.OrdinalIgnoreCase))                return null;            // Parse kßĶ+t qußĶú            var isSuccess = root.TryGetProperty("code", out var codeEl) && codeEl.GetString() == "00";            var orderCode = dataEl.TryGetProperty("orderCode", out var ocEl) ? ocEl.GetInt64() : 0;            var amount    = dataEl.TryGetProperty("amount", out var amEl) ? amEl.GetInt32() : 0;            var desc      = dataEl.TryGetProperty("description", out var dEl) ? dEl.GetString() ?? "" : "";            return new GatewayWebhookData(orderCode, amount, desc, isSuccess);        }        catch        {            return null;        }    }    private static string ComputeHmacSha256(string data, string key)    {        var keyBytes  = Encoding.UTF8.GetBytes(key);        var dataBytes = Encoding.UTF8.GetBytes(data);        using var hmac = new HMACSHA256(keyBytes);        var hash = hmac.ComputeHash(dataBytes);        return Convert.ToHexString(hash).ToLowerInvariant();    }    // GöĮGöĮGöĮ Internal DTOs (chß+ë d+Ķng -æß+â deserialize response PayOS) GöĮGöĮGöĮ    private class PayOsApiResponse    {        [JsonPropertyName("code")]   public string? Code { get; set; }        [JsonPropertyName("desc")]   public string? Desc { get; set; }        [JsonPropertyName("data")]   public PayOsResponseData? Data { get; set; }    }    private class PayOsResponseData    {        [JsonPropertyName("checkoutUrl")]    public string? CheckoutUrl    { get; set; }        [JsonPropertyName("qrCode")]         public string? QrCode         { get; set; }        [JsonPropertyName("paymentLinkId")]  public string? PaymentLinkId  { get; set; }        [JsonPropertyName("orderCode")]      public long    OrderCode       { get; set; }        [JsonPropertyName("status")]         public string? Status          { get; set; }    }}